import { describe, expect, it } from 'vitest';

import {
  adist,
  assessKeystrokeLeak,
  fpDistance,
  keyA1,
  keyA2,
  keyL,
  keyLeaks,
  keyM,
  keyN,
  KeystrokeLeakMaster,
  mismatchPenalty,
  type KeyAcoustic,
} from '../src/keystroke-leak-detector';

describe('adist (mirrors adist_self / adist_comm)', () => {
  it('is zero at a point with itself', () => {
    for (const a of [0, 1, 5, 42]) {
      expect(adist(a, a)).toBe(0);
    }
  });

  it('is the absolute difference and symmetric', () => {
    expect(adist(40, 41)).toBe(1);
    expect(adist(41, 40)).toBe(1);
    expect(adist(12, 38)).toBe(26);
    expect(adist(38, 12)).toBe(26);
  });

  it('saturates at zero (Nat truncated subtraction)', () => {
    expect(adist(0, 0)).toBe(0);
    expect(Math.max(0, 4 - 9)).toBe(0);
  });
});

describe('fpDistance (mirrors fpDistance / fpDistance_self)', () => {
  it('is zero from a signature to itself (self-consistency)', () => {
    expect(fpDistance(keyA1, keyA1)).toBe(0);
    expect(fpDistance(keyL, keyL)).toBe(0);
    expect(fpDistance(keyM, keyM)).toBe(0);
  });

  it('is the summed pointwise adist of aligned bands', () => {
    // 1 + 1 + 0 + 1 = 3
    expect(fpDistance(keyA1, keyA2)).toBe(3);
    // 28 + 17 + 23 + 18 = 86
    expect(fpDistance(keyA1, keyL)).toBe(86);
    // 0 + 0 + 0 + 1 = 1
    expect(fpDistance(keyM, keyN)).toBe(1);
  });

  it('returns the large mismatch sentinel on a length mismatch', () => {
    expect(fpDistance([1, 2, 3], [1, 2])).toBe(mismatchPenalty);
    expect(fpDistance([], [0])).toBe(mismatchPenalty);
    expect(mismatchPenalty).toBeGreaterThan(86);
  });
});

describe('keyLeaks (mirrors leaksB / LeakPresent — separability is the leak)', () => {
  it('fires (leak present) when distinct keys separate beyond sepThreshold', () => {
    // mirrors distinct_keys_leakB
    expect(keyLeaks(keyA1, keyL, { sepThreshold: 12 })).toBe(true);
  });

  it('does not fire on two presses of the same key', () => {
    // mirrors same_key_not_leak
    expect(keyLeaks(keyA1, keyA2, { sepThreshold: 12 })).toBe(false);
  });

  it('does not fire on indistinguishable keys', () => {
    // mirrors indistinct_keys_not_flagged
    expect(keyLeaks(keyM, keyN, { sepThreshold: 12 })).toBe(false);
  });
});

describe('promotion check: assessKeystrokeLeak (leak-detector polarity)', () => {
  it('admits a LEAK when keys are distinguishable (separation > sepThreshold)', () => {
    // mirrors distinct_keys_leak: admitted = leak present, warn the user
    const a = assessKeystrokeLeak(keyA1, keyL, { intraTol: 4, sepThreshold: 12 });
    expect(a.outcome).toBe('claim_admitted');
    expect(a.leaks).toBe(true);
    expect(a.safe).toBe(false);
    expect(a.distance).toBe(86);
    expect(a.limitation).toBe('none');
  });

  it('withholds (SAFE) when keys are indistinguishable within intraTol', () => {
    // mirrors indistinct_keys_safe
    const a = assessKeystrokeLeak(keyM, keyN, { intraTol: 4, sepThreshold: 12 });
    expect(a.outcome).toBe('claim_withheld');
    expect(a.limitation).toBe('indistinguishable_safe');
    expect(a.safe).toBe(true);
    expect(a.leaks).toBe(false);
    expect(a.distance).toBe(1);
  });

  it('withholds (SAFE) for two presses of the same key', () => {
    const a = assessKeystrokeLeak(keyA1, keyA2, { intraTol: 4, sepThreshold: 12 });
    expect(a.outcome).toBe('claim_withheld');
    expect(a.limitation).toBe('indistinguishable_safe');
    expect(a.distance).toBe(3);
  });

  it('reports observation_only in the ambiguous margin (intraTol < d <= sepThreshold)', () => {
    // distance 3 is above intraTol 2 but not beyond sepThreshold 12
    const a = assessKeystrokeLeak(keyA1, keyA2, { intraTol: 2, sepThreshold: 12 });
    expect(a.outcome).toBe('observation_only');
    expect(a.limitation).toBe('ambiguous_margin');
    expect(a.leaks).toBe(false);
    expect(a.safe).toBe(false);
    expect(a.distance).toBe(3);
  });

  it('admits a LEAK at the boundary (distance just over sepThreshold)', () => {
    // distance 3, sepThreshold 2 -> leak
    const a = assessKeystrokeLeak(keyA1, keyA2, { intraTol: 1, sepThreshold: 2 });
    expect(a.outcome).toBe('claim_admitted');
    expect(a.distance).toBe(3);
  });

  it('treats a length mismatch as a separated (leaking) pair', () => {
    const a = assessKeystrokeLeak(keyA1, [40, 22, 15], { intraTol: 4, sepThreshold: 12 });
    expect(a.outcome).toBe('claim_admitted');
    expect(a.distance).toBe(mismatchPenalty);
    expect(a.leaks).toBe(true);
  });

  it('never decodes or identifies a key — it only flags separability', () => {
    // the assessment exposes a distance and a verdict, never a key label
    const a = assessKeystrokeLeak(keyA1, keyL, { intraTol: 4, sepThreshold: 12 });
    expect(Object.keys(a).sort()).toEqual(
      ['distance', 'leaks', 'limitation', 'outcome', 'safe', 'summary'].sort(),
    );
    const probe: KeyAcoustic = keyA1;
    expect(probe.length).toBe(4);
  });
});

describe('KeystrokeLeakMaster (mirrors leak_master)', () => {
  it('every boundary witness holds', () => {
    expect(KeystrokeLeakMaster.fpDistanceSelfZero).toBe(true);
    expect(KeystrokeLeakMaster.sameKeyTight).toBe(true);
    expect(KeystrokeLeakMaster.keysWellSeparated).toBe(true);
    expect(KeystrokeLeakMaster.distinctKeysLeak).toBe(true);
    expect(KeystrokeLeakMaster.distinctKeysLeakB).toBe(true);
    expect(KeystrokeLeakMaster.sameKeyNotLeak).toBe(true);
    expect(KeystrokeLeakMaster.indistinctKeysSafe).toBe(true);
    expect(KeystrokeLeakMaster.indistinctKeysNotFlagged).toBe(true);
  });
});
